{"content":"package com.pinterest.ktlint.ruleset.standard

import com.pinterest.ktlint.core.RuleProvider
import com.pinterest.ktlint.ruleset.standard.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class TrailingCommaOnDeclarationSiteRuleReproductionTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                RuleProvider { WrappingRule() },
                RuleProvider { IndentationRule() },
                RuleProvider { NoSemiRule() }
            ),
        )

    @Test
    fun `Reproduce issue with enum class and trailing comma and no-semi`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        // The input code in the issue seems to already have the semi-colon and trailing comma?
        // Wait, the issue says:
        // "When formatting and validating the following enum class, the ktlint command should exit successfully"
        // And then:
        // "When running ktlint on the above enum class, it is formatted correctly, but the run fails with rule violations"

        // This implies the input code might be slightly different or the same.
        // If I provide the code as "Expected Behavior", it should pass.

        // Let's try to pass the code as is and see if it fails.
        // The issue says: 
        // /home/karl/tasks/ktlint-issue-example/TestEnum.kt:1:1: Missing trailing comma before "}" (trailing-comma-on-declaration-site)
        // /home/karl/tasks/ktlint-issue-example/TestEnum.kt:5:4: Unnecessary semicolon (no-semi)

        // Note that line 1:1 is weird for "Missing trailing comma before '}'" in an enum defined as above.
        // Line 5:4 is where `B;` is.

        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasNoLintViolations()
    }
}
