import com.pinterest.ktlint.core.RuleProvider
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class NoSemicolonsRuleReproductionTest {
    private val noSemicolonsRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { NoSemicolonsRule() }
        )

    @Test
    fun `Given an enum class with trailing comma and semicolon on separate line, it should not report unnecessary semicolon`() {
        val code =
            """
            enum class TestEnum {
                A,
                B,
                ;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
            """.trimIndent()

        noSemicolonsRuleAssertThat(code)
            .hasNoLintViolations()
    }
}
"}

